steps.cmd:
clear; clc; close all;
Kp=10; Ki=2; Kd=1;
tau=0.1; Kp_motor=1;

for k=2:length(t)
    e=r(k)-y(k-1);
    e_int=e_int+e*dt;
    de=(e-e_prev)/dt;
    u=Kp*e+Ki*e_int+Kd*de;
    y(k)=y(k-1)+dt*(-y(k-1)+Kp_motor*u)/tau;
    e_prev=e;
end

figure('Name','PID');
plot(t,r,'r--',t,y,'b-','LineWidth',2);
title('PID Step Response'); xlabel('Time (s)'); ylabel('Output');
legend('Reference','Output'); grid on;
